//vip.opstream14.com/20220326/3253_3c42da6d/index.m3u8"}]}],"time":"47M52S","description":"<p>Hung trạch là một ngôi nhà từng có người chết bất đắc kỳ tử. Linh hồn người chết không tiêu tan, vậy nên hung trạch thường xảy ra những chuyện kỳ lạ. Giang Thước và Tần Nhất Hằng là một cặp đôi cò nhà đất bí ẩn, bọn họ bỏ một số tiền thấp để mua hung trạch nổi tiếng gần xa, sau khi trừ tà thì sẽ bán lại cho người khác. Thế nhưng gần đây bọn họ phát hiện ra là mình đã lọt vào một cái lưới nguy hiểm rình rập khắp nơi.</p>","tmdb":{"type":"tv","id":"113621","season":1,"vote_average":6.833,"vote_count":6},"modified":"2023-04-23T19:58:42.000Z"},{"id":"623f257fe3cd150b39912937","_id":"623f257fe3cd150b39912937","title":"Trắng Đen Sáng Tỏ","origin_name":"The Penalty Zone","slug":"trang-den-sang-to","year":2020,"type":"series","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (44/44)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"trang-den-sang-to-tap-1","link_embed":"https://vip.opstream14.com/share/8deb8d1dd92840f975b6931ab3a3c61e","link_m3u8":"https://vip.opstream14.com/20220326/3254_ad30e064/index.m3u8"},{"name":"2","slug":"2","filename":"trang-den-sang-to-tap-2","link_embed":"https://vip.opstream14.com/share/2067e2650cd701ae71c68080f9dbbdc1","link_m3u8":"https://vip.opstream14.com/20220326/3255_7bf55c7b/index.m3u8"},{"name":"3","slug":"3","filename":"trang-den-sang-to-tap-3","link_embed":"https://vip.opstream14.com/share/2131f8ecf18db66a758f718dc729e00e","link_m3u8":"https://vip.opstream14.com/20220326/3256_13f2d293/index.m3u8"},{"name":"4","slug":"4","filename":"trang